import{_ as t,c as n,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Build-Toolchain: Validierung & CI | Agent Skills","description":"Lernen Sie die Agent Skills Build-Toolchain: Validierung mit pnpm validate, Build mit pnpm build, Entwicklungsablauf mit pnpm dev, GitHub Actions CI-Integration, Testfall-Extraktion und LLM-Automatisierungsbewertung.","frontmatter":{"title":"Build-Toolchain: Validierung & CI | Agent Skills","sidebarTitle":"Build-Toolchain","subtitle":"Build-Toolchain: Validierung & CI","description":"Lernen Sie die Agent Skills Build-Toolchain: Validierung mit pnpm validate, Build mit pnpm build, Entwicklungsablauf mit pnpm dev, GitHub Actions CI-Integration, Testfall-Extraktion und LLM-Automatisierungsbewertung.","tags":["Build-Tools","CI/CD","Automatisierung","Code-Validierung"],"prerequisite":["start-getting-started","start-installation","advanced-rule-authoring"]},"headers":[],"relativePath":"de/vercel-labs/agent-skills/advanced/build-toolchain/index.md","filePath":"de/vercel-labs/agent-skills/advanced/build-toolchain/index.md"}'),l={name:"de/vercel-labs/agent-skills/advanced/build-toolchain/index.md"};function r(s,e,d,o,u,c){return a(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="build-toolchain-verwendung" tabindex="-1">Build-Toolchain-Verwendung <a class="header-anchor" href="#build-toolchain-verwendung" aria-label="Permalink to &quot;Build-Toolchain-Verwendung&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><p>Nach Abschluss dieser Lektion werden Sie können:</p><ul><li>✅ <code>pnpm validate</code> verwenden, um das Format und die Vollständigkeit der Regeldateien zu validieren</li><li>✅ <code>pnpm build</code> verwenden, um AGENTS.md und test-cases.json zu generieren</li><li>✅ Den Build-Ablauf verstehen: parse → validate → group → sort → generate</li><li>✅ GitHub Actions CI für automatische Validierung und Build konfigurieren</li><li>✅ Testfälle für die LLM-Automatisierungsbewertung extrahieren</li><li>✅ <code>pnpm dev</code> für den schnellen Entwicklungsablauf (build + validate) verwenden</li></ul><h2 id="kernarchitektur" tabindex="-1">Kernarchitektur <a class="header-anchor" href="#kernarchitektur" aria-label="Permalink to &quot;Kernarchitektur&quot;">​</a></h2><p>Die Build-Toolchain besteht aus drei Hauptteilen:</p><p><strong>1. Build-Toolchain</strong> (<code>packages/react-best-practices-build/</code>)</p><ul><li>Regeldateien parsen</li><li>AGENTS.md generieren</li><li>Testfälle extrahieren</li></ul><p><strong>2. Regeldateien</strong> (<code>skills/react-best-practices/rules/</code>)</p><ul><li>57 React-Performance-Optimierungsregeln</li><li>Markdown-Format, folgt den Template-Spezifikationen</li></ul><p><strong>3. Deployment-Skripte</strong> (<code>skills/claude.ai/vercel-deploy-claimable/</code>)</p><ul><li>Ein-Klick-Deployment auf Vercel</li><li>Automatische Framework-Erkennung</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p><strong>Rolle der Build-Toolchain</strong>:</p><p>Agent Skills Regelbibliothek besteht im Wesentlichen aus 57 unabhängigen Markdown-Dateien, aber Claude benötigt eine strukturierte AGENTS.md, um sie effizient nutzen zu können. Die Build-Toolchain übernimmt:</p><ol><li><strong>Regeldateien parsen</strong>: Extrahieren von title, impact, examples usw. aus Markdown</li><li><strong>Vollständigkeit validieren</strong>: Überprüfung, ob jede Regel title, explanation und Codebeispiele hat</li><li><strong>Gruppieren und Sortieren</strong>: Gruppierung nach Kapiteln, Sortierung nach Titel, Zuweisung von IDs (1.1, 1.2...)</li><li><strong>Dokumentation generieren</strong>: Ausgabe von formatiertem AGENTS.md und test-cases.json</li></ol><p><strong>Build-Ablauf</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rules/*.md (57 Dateien)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[parser.ts] Markdown parsen</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[validate.ts] Vollständigkeit validieren</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[build.ts] Gruppieren → Sortieren → AGENTS.md generieren</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[extract-tests.ts] Testfälle extrahieren → test-cases.json</span></span></code></pre></div><p><strong>Vier Kernbefehle</strong>:</p><table tabindex="0"><thead><tr><th>Befehl</th><th>Funktion</th><th>Geeignete Szenarien</th></tr></thead><tbody><tr><td><code>pnpm validate</code></td><td>Validierung des Formats und der Vollständigkeit aller Regeldateien</td><td>Vor Commit-Prüfung, CI-Validierung</td></tr><tr><td><code>pnpm build</code></td><td>Generierung von AGENTS.md und test-cases.json</td><td>Nach Regeldateien-Modifikation, vor Veröffentlichung</td></tr><tr><td><code>pnpm dev</code></td><td>Ausführung von build + validate (Entwicklungsablauf)</td><td>Schnelle Iteration, Entwicklung neuer Regeln</td></tr><tr><td><code>pnpm extract-tests</code></td><td>Alleinige Extraktion von Testfällen (ohne Neubuild)</td><td>Nur Aktualisierung von Testdaten</td></tr></tbody></table><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p><strong>Kernpunkte</strong>:</p><ol><li><strong>Validierung (validate)</strong>: Validierung des Regelformats, der Vollständigkeit, des Impact-Levels</li><li><strong>Build (build)</strong>: Regeln parsen → Gruppieren → Sortieren → AGENTS.md generieren</li><li><strong>Test-Extraktion (extract-tests)</strong>: Extraktion von bad/good-Beispielen aus examples</li><li><strong>Entwicklungsablauf (dev)</strong>: <code>validate + build + extract-tests</code> für schnelle Iteration</li><li><strong>CI-Integration</strong>: GitHub Actions automatisieren Validierung und Build, verhindern das Einreichen von fehlerhaftem Code</li></ol><p><strong>Best-Practices-Mantra</strong>:</p><blockquote><p>Erst validieren, dann builden, dann commiten dev-Befehl für den kompletten Ablauf, ein Schritt für hohe Effizienz CI automatisch prüfen, PR-Review einfacher Versionsnummern müssen aktualisiert werden, metadata muss bearbeitet werden</p></blockquote><hr><h2 id="anhang-quellcodereferenz" tabindex="-1">Anhang: Quellcodereferenz <a class="header-anchor" href="#anhang-quellcodereferenz" aria-label="Permalink to &quot;Anhang: Quellcodereferenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcodepositionen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>package.json Skriptdefinition</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/package.json" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/package.json</code></a></td><td>6-12</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Regelparser</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/src/parser.ts" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/src/parser.ts</code></a></td><td>Ganze Datei</td></tr><tr><td>Regelvalidierungsfunktion</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/packages/react-best-practices-build/src/validate.ts" target="_blank" rel="noreferrer"><code>packages/react-best-practices-build/src/validate.ts</code></a></td><td>21-66</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>`,28)])])}const h=t(l,[["render",r]]);export{g as __pageData,h as default};
